"""Channel strategies — the pluggable delivery mechanisms."""
from __future__ import annotations
from abc import ABC, abstractmethod
from typing import List

from models import Message, ChannelType, InvalidContactError


# ── WHY THIS CLASS ───────────────────────────────────────────────────────────
# The Strategy seam. The service calls send(message) and never knows whether
# it's SMTP, a push gateway, or an in-app store. New channel = new subclass.
# 🎙️ "This single-method interface is why adding a channel is zero core change."
class Channel(ABC):
    channel_type: ChannelType

    @abstractmethod
    def send(self, message: Message) -> None:
        """Deliver one rendered message. Raise NotificationError on failure."""


class EmailChannel(Channel):
    channel_type = ChannelType.EMAIL

    def __init__(self) -> None:
        self.sent: List[Message] = []  # stand-in for an SMTP outbox

    def send(self, message: Message) -> None:
        # WHY: each channel enforces its own delivery requirement. A bad email
        #      surfaces as a per-channel failure, not a crash of the fan-out.
        if "@" not in message.recipient:
            raise InvalidContactError(f"bad email address: {message.recipient!r}")
        self.sent.append(message)


class SmsChannel(Channel):
    channel_type = ChannelType.SMS

    def __init__(self) -> None:
        self.sent: List[Message] = []

    def send(self, message: Message) -> None:
        digits = message.recipient.lstrip("+")
        if not digits.isdigit():
            raise InvalidContactError(f"bad phone number: {message.recipient!r}")
        self.sent.append(message)


class PushChannel(Channel):
    channel_type = ChannelType.PUSH

    def __init__(self) -> None:
        self.sent: List[Message] = []

    def send(self, message: Message) -> None:
        if not message.recipient:
            raise InvalidContactError("missing device token")
        self.sent.append(message)


class InAppChannel(Channel):
    channel_type = ChannelType.IN_APP

    def __init__(self) -> None:
        self.sent: List[Message] = []

    def send(self, message: Message) -> None:
        # In-app always has a "recipient" (the user id) — most reliable channel.
        self.sent.append(message)


class FlakyChannel(Channel):
    # ── WHY THIS CLASS (test aid) ───────────────────────────────────────────
    # Fails the first `fail_times` calls, then succeeds — lets us prove the
    # retry path without real network flakiness.
    # 🎙️ "A scripted fake: fail twice, succeed on the third — tests retry."
    def __init__(self, channel_type: ChannelType, fail_times: int) -> None:
        self.channel_type = channel_type
        self._remaining_failures = fail_times
        self.sent: List[Message] = []

    def send(self, message: Message) -> None:
        if self._remaining_failures > 0:
            self._remaining_failures -= 1
            raise InvalidContactError("transient delivery error")
        self.sent.append(message)

"""TemplateRegistry, RateLimiter, and the NotificationService orchestrator."""
from __future__ import annotations
import time
from collections import defaultdict, deque
from contextlib import contextmanager
from typing import Callable, Dict, Iterator, List, Optional, Set

from channels import Channel
from models import (
    ChannelType,
    DeliveryResult,
    DeliveryStatus,
    InvalidContactError,
    Message,
    NotificationError,
    NotificationEvent,
    NotificationType,
    UnknownUserError,
    User,
)


class _SafeDict(dict):
    # WHY: a missing personalization key renders as empty instead of crashing.
    def __missing__(self, key):  # noqa: ANN001
        return ""


class Template:
    """A subject/body pair with {placeholders} filled from user + event data."""

    def __init__(self, subject_tpl: str, body_tpl: str) -> None:
        self._subject = subject_tpl
        self._body = body_tpl

    def render(self, user: User, data: dict) -> tuple[str, str]:
        ctx = _SafeDict(name=user.name, **data)
        return self._subject.format_map(ctx), self._body.format_map(ctx)


class TemplateRegistry:
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # Personalization lives here, keyed by (type, channel). The service asks it
    # for a ready-to-send Message — separation of "what to say" from "how to send".
    def __init__(self) -> None:
        self._templates: Dict[tuple, Template] = {}

    def register(self, t: NotificationType, ch: ChannelType, template: Template) -> None:
        self._templates[(t, ch)] = template

    def render(self, t: NotificationType, ch: ChannelType, user: User, data: dict) -> Message:
        recipient = user.address_for(ch)
        if recipient is None:
            # WHY: user wants this channel but has no handle for it — explicit error.
            raise InvalidContactError(f"user {user.id} has no handle for {ch.value}")
        template = self._templates.get((t, ch))
        if template is None:
            subject, body = t.value, f"Hi {user.name}"   # safe default
        else:
            subject, body = template.render(user, data)
        return Message(channel=ch, recipient=recipient, subject=subject, body=body)


class RateLimiter:
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # Sliding-window frequency cap per user. allow() is a CHECK-THEN-ACT: it
    # reads the window, checks the count, then records — the race we guard in §9.
    # 🎙️ "Time is injected so tests move the clock instead of sleeping."
    def __init__(self, now_fn: Callable[[], float] = time.monotonic) -> None:
        self._now = now_fn
        self._events: Dict[str, deque] = defaultdict(deque)

    def allow(self, user_id: str, max_count: int, window_seconds: int) -> bool:
        now = self._now()
        dq = self._events[user_id]
        cutoff = now - window_seconds
        while dq and dq[0] <= cutoff:      # trim timestamps older than the window
            dq.popleft()
        if len(dq) >= max_count:
            return False                   # over the cap — caller records RATE_LIMITED
        dq.append(now)                     # the "act" half of check-then-act
        return True


class NotificationService:
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # The brain / Facade. Owns the registries and routes every event. This is
    # the CLEAN, single-threaded core — no locks live here (see §9 for the
    # thread-safe subclass that overrides exactly one method, _lock).
    # 🎙️ "Every operation flows through here; send() ties the whole pipeline."
    def __init__(
        self,
        template_registry: TemplateRegistry,
        rate_limiter: RateLimiter,
        retry_attempts: int = 2,
    ) -> None:
        self._users: Dict[str, User] = {}
        self._channels: Dict[ChannelType, Channel] = {}
        self._subscribers: Dict[NotificationType, Set[str]] = defaultdict(set)  # Observer topics
        self._templates = template_registry
        self._rate = rate_limiter
        self._retry_attempts = retry_attempts

    # ── Template Method hook ────────────────────────────────────────────────
    @contextmanager
    def _lock(self, user_id: str) -> Iterator[None]:
        # WHY: does nothing in the clean core. The thread-safe subclass overrides
        #      this with a real per-user lock. Zero lock code in this file.
        yield

    # ── registration ────────────────────────────────────────────────────────
    def register_user(self, user: User) -> None:
        self._users[user.id] = user

    def register_channel(self, channel: Channel) -> None:
        self._channels[channel.channel_type] = channel

    def _require_user(self, user_id: str) -> User:
        # WHY: validate at the public boundary before mutating any state.
        user = self._users.get(user_id)
        if user is None:
            raise UnknownUserError(f"no such user: {user_id}")
        return user

    # ── subscriptions (Observer) ─────────────────────────────────────────────
    def subscribe(self, user_id: str, t: NotificationType, channels: Set[ChannelType]) -> None:
        user = self._require_user(user_id)
        if not channels:
            raise NotificationError("must subscribe with at least one channel")
        user.preference.subscribed_types.add(t)
        user.preference.channels_by_type[t] = set(channels)
        self._subscribers[t].add(user_id)   # register in the topic map

    def unsubscribe(self, user_id: str, t: NotificationType) -> None:
        user = self._require_user(user_id)
        user.preference.subscribed_types.discard(t)
        user.preference.channels_by_type.pop(t, None)
        self._subscribers[t].discard(user_id)

    def opt_out(self, user_id: str) -> None:
        self._require_user(user_id).preference.opted_out = True

    # ── the core operation ───────────────────────────────────────────────────
    def send(self, event: NotificationEvent) -> List[DeliveryResult]:
        # WHY: snapshot the subscriber set so a concurrent subscribe/unsubscribe
        #      can't mutate the set we're iterating (RuntimeError otherwise).
        recipients = list(self._subscribers.get(event.type, ()))
        results: List[DeliveryResult] = []
        for uid in recipients:
            results.extend(self._deliver_to_user(uid, event))
        return results

    def _deliver_to_user(self, uid: str, event: NotificationEvent) -> List[DeliveryResult]:
        user = self._users.get(uid)
        if user is None:                    # user removed mid-fan-out: skip safely
            return []
        pref = user.preference
        if pref.opted_out:
            return [DeliveryResult(uid, event.type, None, DeliveryStatus.OPTED_OUT)]
        if not pref.is_subscribed(event.type):
            return []

        # WHY: the check-then-act lives inside _lock. No-op here; real lock in §9.
        with self._lock(uid):
            allowed = self._rate.allow(uid, pref.max_per_window, pref.window_seconds)
        if not allowed:
            return [DeliveryResult(uid, event.type, None, DeliveryStatus.RATE_LIMITED)]

        results: List[DeliveryResult] = []
        for ch_type in pref.channels_for(event.type):
            channel = self._channels.get(ch_type)
            if channel is None:
                results.append(
                    DeliveryResult(uid, event.type, ch_type, DeliveryStatus.FAILED, "no channel registered")
                )
                continue
            results.append(self._send_with_retry(user, event, ch_type, channel))
        return results

    def _send_with_retry(self, user, event, ch_type, channel) -> DeliveryResult:
        last_err = ""
        for attempt in range(1, self._retry_attempts + 1):
            try:
                message = self._templates.render(event.type, ch_type, user, event.data)
                channel.send(message)
                return DeliveryResult(user.id, event.type, ch_type, DeliveryStatus.SENT, f"attempt {attempt}")
            except NotificationError as e:
                last_err = str(e)   # transient: try again until attempts exhausted
        return DeliveryResult(user.id, event.type, ch_type, DeliveryStatus.FAILED, last_err)
